23	int main(int argc, char* argv[])
24	{
25	    if (argc < 7 || argc > 9) {
26	        FT_LOG_ERROR("./bin/bert_gemm batch_size \\ \n"
27	                     "                seq_len \\ \n"
28	                     "                head_number \\ \n"
29	                     "                size_per_head \\ \n"
30	                     "                data_type \\ \n"
31	                     "                int8_mode \\ \n"
32	                     "                tensor_para_size \\\n"
33	                     "                is_append (append new config into exist gemm_config.ini or not)");
34	        FT_LOG_ERROR("e.g. ./bin/bert_gemm 1 32 12 64 0 0 1 1");
35	        return 0;
36	    }
37	
38	    const int                batch_size    = atoi(argv[1]);
39	    const int                seq_len       = atoi(argv[2]);
40	    const int                head_num      = atoi(argv[3]);
41	    const int                size_per_head = atoi(argv[4]);
42	    const ft::CublasDataType data_type     = static_cast<ft::CublasDataType>(atoi(argv[5]));  // 0 FP32, 1 FP16, 2 BF 16
43	    const int                int8_mode     = atoi(argv[6]);
44	    const int                tensor_para_size = argc < 8 ? 1 : atoi(argv[7]);
45	    const bool               is_append        = argc < 9 ? false : (bool)(atoi(argv[8]));
46	
47	    const int inter_size = 4 * head_num * size_per_head;
48	    FT_CHECK_WITH_INFO(
49	        head_num % tensor_para_size == 0,
50	        ft::fmtstr("[ERROR] head_num (%d) %% tensor_para_size (%d) != 0", head_num, tensor_para_size));
51	    FT_LOG_INFO("arguments:");
52	    FT_LOG_INFO("  batch_size: %d", batch_size);
53	    FT_LOG_INFO("  head_num: %d", head_num);
54	    FT_LOG_INFO("  size_per_head: %d", size_per_head);
55	    FT_LOG_INFO("  data_type: %d", data_type);
56	    FT_LOG_INFO("  int8_mode: %d", int8_mode);
57	    FT_LOG_INFO("  tensor_para_size: %d", tensor_para_size);
58	    FT_LOG_INFO("  is_append: %d", (int)is_append);
59	    std::cout << std::endl;
60	
61	    void*  gemm_test_buf;
62	    size_t buf_size_in_byte =
63	        ft::calGemmTestBufSizeInByte(batch_size, seq_len, head_num, size_per_head, inter_size, 0, int8_mode, data_type);
64	    size_t total, free;
65	    ft::check_cuda_error(cudaMemGetInfo(&free, &total));
66	    if (free < buf_size_in_byte + 10 * 1024 * 1024) {
67	        FT_LOG_ERROR(" There is no enough device memory for gemm test!\n"
68	                     " %ld Bytes is needed, but only %ld Bytes is free.",
69	                     buf_size_in_byte,
70	                     free);
71	        gemm_test_buf = NULL;
72	        return -1;
73	    }
74	    else {
75	        ft::deviceMalloc(reinterpret_cast<char**>(&gemm_test_buf), buf_size_in_byte, false);
76	    }
77	
78	    if (int8_mode != 0) {
79	        ft::generate_encoder_igemm_config(batch_size, seq_len, head_num, size_per_head, gemm_test_buf, is_append);
80	    }
81	    else if (data_type == ft::FLOAT_DATATYPE) {
82	        ft::generate_encoder_gemm_config<float>(
83	            batch_size, seq_len, head_num, size_per_head, gemm_test_buf, is_append, tensor_para_size);
84	    }
85	    else if (data_type == ft::HALF_DATATYPE) {
86	        ft::generate_encoder_gemm_config<half>(
87	            batch_size, seq_len, head_num, size_per_head, gemm_test_buf, is_append, tensor_para_size);
88	    }
89	#ifdef ENABLE_BF16
90	    else if (data_type == ft::BFLOAT16_DATATYPE) {
91	        ft::generate_encoder_gemm_config<__nv_bfloat16>(
92	            batch_size, seq_len, head_num, size_per_head, gemm_test_buf, is_append, tensor_para_size);
93	    }
94	#endif
95	    else {
96	        FT_LOG_ERROR("data type only supports fp32(0), fp16(1), bf16(2). \n");
97	        return -1;
98	    }
99	
100	    ft::check_cuda_error(cudaFree(gemm_test_buf));
101	    return 0;
102	}
