21	
22	template<typename T>
23	void Bert<T>::initialize()
24	{
25	    if (std::is_same<T, half>::value
26	        && (attention_type_ == AttentionType::FUSED_MHA || attention_type_ == AttentionType::FUSED_PADDED_MHA)) {
27	        fused_attention_layer_ = new FusedAttentionLayer<T>(0,
28	                                                            0,
29	                                                            head_num_ / tensor_para_.world_size_,
30	                                                            size_per_head_,
31	                                                            head_num_ * size_per_head_,
32	                                                            sm_,
33	                                                            q_scaling_,
34	                                                            stream_,
35	                                                            cublas_wrapper_,
36	                                                            allocator_,
37	                                                            is_free_buffer_after_forward_,
38	                                                            sparse_);
39	    }
40	    unfused_attention_layer_ = new UnfusedAttentionLayer<T>(0,
41	                                                            0,
42	                                                            head_num_ / tensor_para_.world_size_,
43	                                                            size_per_head_,
44	                                                            head_num_ * size_per_head_,
45	                                                            q_scaling_,
46	                                                            stream_,
47	                                                            cublas_wrapper_,
48	                                                            allocator_,
49	                                                            is_free_buffer_after_forward_,
50	                                                            sparse_);
51	
52	    bool use_gated_activation = activation_type_ == ActivationType::GeGLU || activation_type_ == ActivationType::ReGLU;
53	    if (activation_type_ == ActivationType::Gelu) {
54	        ffn_layer_ = new TensorParallelGeluFfnLayer<T>(0,
55	                                                       0,
56	                                                       head_num_,
57	                                                       size_per_head_,
58	                                                       0,  // expert_num
59	                                                       inter_size_,
60	                                                       tensor_para_,
61	                                                       stream_,
62	                                                       cublas_wrapper_,
63	                                                       allocator_,
64	                                                       true,
65	                                                       is_free_buffer_after_forward_,
66	                                                       sparse_,
67	                                                       0,
68	                                                       use_gated_activation,
69	                                                       custom_all_reduce_comm_,
70	                                                       enable_custom_all_reduce_);
71	    }
72	    else if (activation_type_ == ActivationType::Relu) {
73	        ffn_layer_ = new TensorParallelReluFfnLayer<T>(0,
74	                                                       0,
75	                                                       head_num_,
76	                                                       size_per_head_,
77	                                                       0,  // expert_num
78	                                                       inter_size_,
79	                                                       tensor_para_,
80	                                                       stream_,
81	                                                       cublas_wrapper_,
82	                                                       allocator_,
83	                                                       true,
84	                                                       is_free_buffer_after_forward_,
85	                                                       sparse_,
86	                                                       0,
87	                                                       use_gated_activation,
88	                                                       custom_all_reduce_comm_,
89	                                                       enable_custom_all_reduce_);
90	    }
91	}
92	
93	template<typename T>
94	Bert<T>::Bert(size_t                              max_batch_size,
95	              size_t                              max_seq_len,
96	              size_t                              head_num,
97	              size_t                              size_per_head,
98	              size_t                              inter_size,
99	              size_t                              num_layer,
100	              int                                 sm,
101	              float                               q_scaling,
102	              cudaStream_t                        stream,
103	              cublasMMWrapper*                    cublas_wrapper,
104	              IAllocator*                         allocator,
105	              bool                                is_free_buffer_after_forward,
106	              AttentionType                       attention_type,
107	              bool                                sparse,
108	              ActivationType                      activation_type,
109	              LayerNormType                       layernorm_type,
110	              NcclParam                           tensor_para,
111	              NcclParam                           pipeline_para,
112	              std::shared_ptr<AbstractCustomComm> custom_all_reduce_comm,
113	              bool                                enable_custom_all_reduce):
