216	template<typename T>
217	void Bert<T>::allocateBuffer(size_t batch_size, size_t seq_len)
218	{
219	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
220	    h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
221	    padding_offset_         = (int*)allocator_->reMalloc(padding_offset_, sizeof(int) * batch_size * seq_len, false);
222	    trt_mha_padding_offset_ =
223	        (int*)allocator_->reMalloc(trt_mha_padding_offset_, sizeof(int) * (2 * batch_size + 1), false);
224	
225	    attention_mask_ = (T*)allocator_->reMalloc(attention_mask_, sizeof(T) * batch_size * seq_len * seq_len, false);
226	
227	    bert_in_buffer_ =
228	        (T*)allocator_->reMalloc(bert_in_buffer_, sizeof(T) * batch_size * seq_len * head_num_ * size_per_head_, false);
229	    attn_out_buf_    = (T*)allocator_->reMalloc(attn_out_buf_, sizeof(T) * batch_size * seq_len * hidden_units_, false);
230	    bert_out_buffer_ = (T*)allocator_->reMalloc(
231	        bert_out_buffer_, sizeof(T) * batch_size * seq_len * head_num_ * size_per_head_, false);
232	
233	    if (layernorm_type_ == LayerNormType::post_layernorm) {
234	        normed_from_tensor_  = nullptr;
235	        normed_attn_out_buf_ = nullptr;
236	    }
237	    else {
238	        normed_from_tensor_ =
239	            (T*)allocator_->reMalloc(normed_from_tensor_, sizeof(T) * batch_size * seq_len * hidden_units_, false);
240	        normed_attn_out_buf_ =
241	            (T*)allocator_->reMalloc(normed_attn_out_buf_, sizeof(T) * batch_size * seq_len * hidden_units_, false);
242	    }
243	    is_allocate_buffer_ = true;
244	}
