246	template<typename T>
247	void Bert<T>::freeBuffer()
248	{
249	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
250	    if (is_allocate_buffer_) {
251	        allocator_->free((void**)(&h_pinned_token_num_ptr_), true);
252	        allocator_->free((void**)(&padding_offset_));
253	        allocator_->free((void**)(&trt_mha_padding_offset_));
254	
255	        allocator_->free((void**)(&attention_mask_));
256	        allocator_->free((void**)(&bert_in_buffer_));
257	        allocator_->free((void**)(&attn_out_buf_));
258	        allocator_->free((void**)(&bert_out_buffer_));
259	
260	        if (layernorm_type_ == LayerNormType::post_layernorm) {
261	            normed_from_tensor_  = nullptr;
262	            normed_attn_out_buf_ = nullptr;
263	        }
264	        else {
265	            allocator_->free((void**)(&normed_from_tensor_));
266	            allocator_->free((void**)(&normed_attn_out_buf_));
267	        }
268	        is_allocate_buffer_ = false;
269	    }
270	}
