305	template<typename T>
306	void Bert<T>::forward(std::vector<Tensor>*       output_tensors,
307	                      const std::vector<Tensor>* input_tensors,
308	                      const BertWeight<T>*       bert_weights)
309	{
310	    TensorMap input_tensors_map =
311	        TensorMap({{"input_hidden_state", input_tensors->at(0)}, {"sequence_lengths", input_tensors->at(1)}});
312	    TensorMap output_tensors_map = TensorMap({{"output_hidden_state", output_tensors->at(0)}});
313	    forward(&output_tensors_map, &input_tensors_map, bert_weights);
314	}
315	
316	template<typename T>
317	void Bert<T>::forward(TensorMap* output_tensors, TensorMap* input_tensors, const BertWeight<T>* bert_weights)
318	{
319	    // input_tensors:
320	    //      input_hidden_state [batch, seqlen, hidden]
321	    //      sequence_lengths [batch]
322	    // output tensors:
323	    //      output_hidden_state [batch, seqlen, hidden]
324	
325	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
326	    const size_t request_batch_size = input_tensors->at("input_hidden_state").shape[0];
327	    const size_t request_seq_len    = input_tensors->at("input_hidden_state").shape[1];
328	    FT_CHECK(input_tensors->size() >= 2);
329	    FT_CHECK(request_batch_size == input_tensors->at("sequence_lengths").shape[0]);
330	    FT_CHECK(input_tensors->at("input_hidden_state").shape.size() == 3);
331	    FT_CHECK(input_tensors->at("sequence_lengths").shape.size() == 1);
332	    allocateBuffer(request_batch_size, request_seq_len);
333	
334	    const int* sequence_lengths = input_tensors->at("sequence_lengths").getPtr<int>();
335	
336	    DataType     data_type        = getTensorType<T>();
337	    const size_t local_batch_size = getLocalBatchSize(request_batch_size, request_seq_len, pipeline_para_.world_size_);
338	    FT_CHECK(request_batch_size % local_batch_size == 0);
339	    const size_t  iteration_num  = request_batch_size / local_batch_size;
340	    AttentionType attention_type = attention_type_;
341	    if (fused_attention_layer_ == nullptr || fused_attention_layer_->isValidSeqLen(request_seq_len) == false) {
342	        if (attention_type == AttentionType::FUSED_MHA) {
343	            FT_LOG_WARNING("Because the input is invalid for fused mha, switch to unfused mha.");
344	            attention_type = AttentionType::UNFUSED_MHA;
345	        }
346	        else if (attention_type == AttentionType::FUSED_PADDED_MHA) {
347	            FT_LOG_WARNING("Because the input is invalid for fused mha, switch to unfused mha.");
348	            attention_type = AttentionType::UNFUSED_PADDED_MHA;
349	        }
350	    }
351	
352	    for (uint ite = 0; ite < iteration_num; ite++) {
353	        Tensor*      padding_offset_tensor_ptr = nullptr;
354	        const size_t hidden_offset             = ite * local_batch_size * request_seq_len * hidden_units_;
355	        size_t       h_token_num               = 0;
356	
357	        T* bert_input_ptr;
358	        T* bert_output_ptr;
359	
360	        switch (attention_type) {
361	            case AttentionType::UNFUSED_MHA: {
362	                invokeBuildEncoderAttentionMask(
363	                    attention_mask_,
364	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
365	                    local_batch_size,
366	                    request_seq_len,
367	                    stream_);
368	                sync_check_cuda_error();
369	                invokeGetPaddingOffset(
370	                    h_pinned_token_num_ptr_,
371	                    &h_token_num,
372	                    padding_offset_,
373	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
374	                    local_batch_size,
375	                    request_seq_len,
376	                    stream_);
377	
378	                invokeRemovePadding(bert_in_buffer_,
379	                                    input_tensors->at("input_hidden_state").getPtrWithOffset<T>(hidden_offset),
380	                                    padding_offset_,
381	                                    h_token_num,
382	                                    head_num_ * size_per_head_,
383	                                    stream_);
384	                sync_check_cuda_error();
385	
386	                padding_offset_tensor_ptr =
387	                    new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{h_token_num}, padding_offset_);
388	                bert_input_ptr  = bert_in_buffer_;
389	                bert_output_ptr = bert_out_buffer_;
390	                sync_check_cuda_error();
391	                break;
392	            }
393	            case AttentionType::UNFUSED_PADDED_MHA: {
394	                invokeBuildEncoderAttentionMask(
395	                    attention_mask_,
396	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
397	                    local_batch_size,
398	                    request_seq_len,
399	                    stream_);
400	                sync_check_cuda_error();
401	                h_token_num     = local_batch_size * request_seq_len;
402	                bert_input_ptr  = input_tensors->at("input_hidden_state").getPtrWithOffset<T>(hidden_offset);
403	                bert_output_ptr = output_tensors->at("output_hidden_state").getPtrWithOffset<T>(hidden_offset);
404	                padding_offset_tensor_ptr = new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{0}, nullptr);
405	                sync_check_cuda_error();
406	                break;
407	            }
408	            case AttentionType::FUSED_MHA: {
409	                invokeGetPaddingOffset(
410	                    h_pinned_token_num_ptr_,
411	                    &h_token_num,
412	                    padding_offset_,
413	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
414	                    local_batch_size,
415	                    request_seq_len,
416	                    stream_);
417	
418	                invokeRemovePadding(bert_in_buffer_,
419	                                    input_tensors->at("input_hidden_state").getPtrWithOffset<T>(hidden_offset),
420	                                    padding_offset_,
421	                                    h_token_num,
422	                                    head_num_ * size_per_head_,
423	                                    stream_);
424	                sync_check_cuda_error();
425	
426	                invokeGetTrtPaddingOffset(
427	                    trt_mha_padding_offset_,
428	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
429	                    local_batch_size,
430	                    stream_);
431	
432	                padding_offset_tensor_ptr = new Tensor(
433	                    MEMORY_GPU, TYPE_INT32, std::vector<size_t>{local_batch_size + 1}, trt_mha_padding_offset_);
434	                bert_input_ptr  = bert_in_buffer_;
435	                bert_output_ptr = bert_out_buffer_;
436	                sync_check_cuda_error();
437	                break;
438	            }
439	            case AttentionType::FUSED_PADDED_MHA: {
440	                h_token_num = local_batch_size * request_seq_len;
441	                invokeGetTrtPaddingOffset(
442	                    trt_mha_padding_offset_,
443	                    input_tensors->at("sequence_lengths").getPtrWithOffset<int>(ite * local_batch_size),
444	                    local_batch_size,
445	                    request_seq_len,
446	                    stream_);
447	                sync_check_cuda_error();
448	                padding_offset_tensor_ptr = new Tensor(
449	                    MEMORY_GPU, TYPE_INT32, std::vector<size_t>{local_batch_size * 2 + 1}, trt_mha_padding_offset_);
450	                bert_input_ptr  = input_tensors->at("input_hidden_state").getPtrWithOffset<T>(hidden_offset);
451	                bert_output_ptr = output_tensors->at("output_hidden_state").getPtrWithOffset<T>(hidden_offset);
452	                break;
453	            }
454	            default: {
455	                throw std::runtime_error(std::string("[FT][ERROR] Invalid attention type \n"));
456	            }
457	        }
458	
459	        for (uint l = 0; l < num_layer_; l++) {
460	            if (isValidLayerParallelId(l) == false) {
461	                continue;
462	            }
463	            T* from_tensor = l == 0 ? bert_input_ptr : bert_output_ptr;
464	            T* out_tensor  = bert_output_ptr;
465	
466	            if (isFirstLayerParallelId(l) && pipeline_para_.rank_ != 0 && pipeline_para_.world_size_ > 1) {
467	                ftNcclRecv(from_tensor + h_token_num * hidden_units_ / tensor_para_.world_size_ * tensor_para_.rank_,
468	                           h_token_num * hidden_units_ / tensor_para_.world_size_,
469	                           pipeline_para_.rank_ - 1,
470	                           pipeline_para_,
471	                           stream_);
472	                if (tensor_para_.world_size_ > 1) {
473	                    ftNcclAllGather(from_tensor,
474	                                    from_tensor,
475	                                    h_token_num * hidden_units_ / tensor_para_.world_size_,
476	                                    tensor_para_.rank_,
477	                                    tensor_para_,
478	                                    stream_);
479	                }
480	            }
481	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
482	                invokeGeneralLayerNorm(normed_from_tensor_,
483	                                       from_tensor,
484	                                       bert_weights->bert_layer_weights[l].attn_layernorm_weights.gamma,
485	                                       bert_weights->bert_layer_weights[l].attn_layernorm_weights.beta,
486	                                       layernorm_eps_,
487	                                       h_token_num,
488	                                       hidden_units_,
489	                                       (float*)nullptr,
490	                                       0,
491	                                       stream_);
492	                sync_check_cuda_error();
493	            }
494	            // Attention
495	            {
496	                TensorMap attn_input_tensors{
497	                    {"input_query",
498	                     Tensor{MEMORY_GPU,
499	                            data_type,
500	                            std::vector<size_t>{h_token_num, hidden_units_},
501	                            layernorm_type_ == LayerNormType::pre_layernorm ? normed_from_tensor_ : from_tensor}},
502	                    {"attention_mask",
503	                     Tensor{MEMORY_GPU,
504	                            data_type,
505	                            std::vector<size_t>{local_batch_size, 1, request_seq_len, request_seq_len},
506	                            attention_mask_}}};
507	                attn_input_tensors.insertIfValid("padding_offset", *padding_offset_tensor_ptr);
508	                TensorMap attn_output_tensors(
509	                    {{"hidden_features",
510	                      Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, hidden_units_}, attn_out_buf_}}});
511	
512	                bool use_custom_all_reduce_kernel = false;
513	                std::vector<Tensor> hidden_features{attn_output_tensors.at("hidden_features")};
514	                if (enable_custom_all_reduce_ && custom_all_reduce_comm_ != nullptr) {
515	                    use_custom_all_reduce_kernel =
516	                        custom_all_reduce_comm_->swapInternalBuffer(&hidden_features, h_token_num * hidden_units_);
517	                    attn_output_tensors.at("hidden_features").data = hidden_features[0].data;
518	                }
519	
520	                if (attention_type == AttentionType::FUSED_MHA || attention_type == AttentionType::FUSED_PADDED_MHA) {
521	                    fused_attention_layer_->forward(&attn_output_tensors,
522	                                                    &attn_input_tensors,
523	                                                    &bert_weights->bert_layer_weights[l].attention_weights);
524	                }
525	                else if (attention_type == AttentionType::UNFUSED_MHA
526	                         || attention_type == AttentionType::UNFUSED_PADDED_MHA) {
527	                    unfused_attention_layer_->forward(&attn_output_tensors,
528	                                                      &attn_input_tensors,
529	                                                      &bert_weights->bert_layer_weights[l].attention_weights);
530	                }
531	
532	                if (tensor_para_.world_size_ > 1) {
533	                    if (!use_custom_all_reduce_kernel) {
534	                        ftNcclAllReduceSum(
535	                            attn_out_buf_, attn_out_buf_, h_token_num * hidden_units_, tensor_para_, stream_);
536	                    }
537	                    else {
538	                        custom_all_reduce_comm_->customAllReduce(h_token_num * hidden_units_, stream_);
539	                        attn_output_tensors.at("hidden_features").data = hidden_features[0].data;
540	                    }
541	                    sync_check_cuda_error();
542	                }
543	            }
544	
545	            if (layernorm_type_ == LayerNormType::post_layernorm) {
546	                invokeAddBiasResidualLayerNorm(
547	                    attn_out_buf_,
548	                    from_tensor,
549	                    bert_weights->bert_layer_weights[l].attention_weights.attention_output_weight.bias,
550	                    bert_weights->bert_layer_weights[l].attn_layernorm_weights.gamma,
551	                    bert_weights->bert_layer_weights[l].attn_layernorm_weights.beta,
552	                    layernorm_eps_,
553	                    h_token_num,
554	                    hidden_units_,
555	                    stream_);
556	            }
557	            else if (layernorm_type_ == LayerNormType::pre_layernorm) {
558	                invokeGeneralAddBiasResidualPreLayerNorm(
559	                    attn_out_buf_,
560	                    normed_attn_out_buf_,
561	                    attn_out_buf_,
562	                    from_tensor,
563	                    bert_weights->bert_layer_weights[l].ffn_layernorm_weights.gamma,
564	                    bert_weights->bert_layer_weights[l].ffn_layernorm_weights.beta,
565	                    bert_weights->bert_layer_weights[l].attention_weights.attention_output_weight.bias,
566	                    layernorm_eps_,
567	                    h_token_num,
568	                    hidden_units_,
569	                    (float*)nullptr,
570	                    (float*)nullptr,
571	                    (float*)nullptr,
572	                    (float*)nullptr,
573	                    0,
574	                    stream_);
575	            }
576	            sync_check_cuda_error();
577	
578	            // FFN
579	            {
580	                TensorMap ffn_input_tensors(
581	                    {{"ffn_input",
582	                      Tensor{MEMORY_GPU,
583	                             data_type,
584	                             std::vector<size_t>{h_token_num, hidden_units_},
585	                             layernorm_type_ == LayerNormType::pre_layernorm ? normed_attn_out_buf_ : attn_out_buf_}}});
586	                TensorMap ffn_output_tensors(
587	                    {{"ffn_output",
588	                      Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, hidden_units_}, out_tensor}}});
589	                ffn_layer_->forward(
590	                    &ffn_output_tensors, &ffn_input_tensors, &bert_weights->bert_layer_weights[l].ffn_weights);
591	            }
592	
593	            if (layernorm_type_ == LayerNormType::post_layernorm) {
594	                invokeAddBiasResidualLayerNorm(out_tensor,
595	                                               attn_out_buf_,
596	                                               bert_weights->bert_layer_weights[l].ffn_weights.output_weight.bias,
597	                                               bert_weights->bert_layer_weights[l].ffn_layernorm_weights.gamma,
598	                                               bert_weights->bert_layer_weights[l].ffn_layernorm_weights.beta,
599	                                               layernorm_eps_,
600	                                               h_token_num,
601	                                               hidden_units_,
602	                                               stream_);
603	            }
604	            else if (layernorm_type_ == LayerNormType::pre_layernorm) {
605	                invokeAddBiasResidual(out_tensor,
606	                                      attn_out_buf_,
607	                                      bert_weights->bert_layer_weights[l].ffn_weights.output_weight.bias,
608	                                      h_token_num,
609	                                      hidden_units_,
610	                                      stream_);
611	            }
612	            sync_check_cuda_error();
613	
614	            if (isLastLayerParallelId(l) && pipeline_para_.rank_ != pipeline_para_.world_size_ - 1
615	                && pipeline_para_.world_size_ > 1) {
616	
617	                ftNcclSend(out_tensor + h_token_num * hidden_units_ / tensor_para_.world_size_ * tensor_para_.rank_,
618	                           h_token_num * hidden_units_ / tensor_para_.world_size_,
619	                           pipeline_para_.rank_ + 1,
620	                           pipeline_para_,
621	                           stream_);
622	            }
623	        }  // transformer layers
624	
625	        if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
626	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
627	                invokeGeneralLayerNorm(bert_output_ptr,
628	                                       bert_output_ptr,
629	                                       bert_weights->post_transformer_layernorm_weights.gamma,
630	                                       bert_weights->post_transformer_layernorm_weights.beta,
631	                                       layernorm_eps_,
632	                                       h_token_num,
633	                                       hidden_units_,
634	                                       (float*)nullptr,
635	                                       0,
636	                                       stream_);
637	                sync_check_cuda_error();
638	            }
639	
640	            // post process (rebuild padding)
641	            switch (attention_type) {
642	                case AttentionType::UNFUSED_MHA: {
643	                    invokeRebuildPadding(output_tensors->at("output_hidden_state").getPtrWithOffset<T>(hidden_offset),
644	                                         bert_out_buffer_,
645	                                         padding_offset_,
646	                                         h_token_num,
647	                                         head_num_ * size_per_head_,
648	                                         stream_);
649	                    sync_check_cuda_error();
650	                    break;
651	                }
652	                case AttentionType::UNFUSED_PADDED_MHA: {
653	                    break;
654	                }
655	                case AttentionType::FUSED_MHA: {
656	                    invokeRebuildPadding(output_tensors->at("output_hidden_state").getPtrWithOffset<T>(hidden_offset),
657	                                         bert_out_buffer_,
658	                                         padding_offset_,
659	                                         h_token_num,
660	                                         head_num_ * size_per_head_,
661	                                         stream_);
662	                    sync_check_cuda_error();
663	                    break;
664	                }
665	                case AttentionType::FUSED_PADDED_MHA: {
666	                    break;
667	                }
668	                default: {
669	                    throw std::runtime_error(std::string("[FT][ERROR] Invalid attention type \n"));
670	                }
671	            }
672	        }
673	
674	        if (padding_offset_tensor_ptr != nullptr) {
675	            delete padding_offset_tensor_ptr;
676	        }
677	    }
678	
679	    if (is_free_buffer_after_forward_ == true) {
680	        freeBuffer();
681	    }
682	    sync_check_cuda_error();
683	
684	    if (pipeline_para_.world_size_ > 1) {
685	        ftNcclGroupStart();
686	        const int data_size = request_batch_size * request_seq_len * hidden_units_ / tensor_para_.world_size_;
687	        ftNcclBroadCast(output_tensors->at("output_hidden_state").getPtr<T>() + data_size * tensor_para_.rank_,
688	                        data_size,
689	                        pipeline_para_.world_size_ - 1,
690	                        pipeline_para_,
691	                        stream_);
692	        ftNcclGroupEnd();
693	
694	        sync_check_cuda_error();
695	        if (tensor_para_.world_size_ > 1) {
696	            ftNcclAllGather(output_tensors->at("output_hidden_state").getPtr<T>(),
697	                            output_tensors->at("output_hidden_state").getPtr<T>(),
698	                            data_size,
699	                            tensor_para_.rank_,
700	                            tensor_para_,
701	                            stream_);
702	        }
703	        // throw errors when detected
704	        ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
705	    }
706	    cudaStreamSynchronize(stream_);
707	}
708	
709	template class Bert<float>;
710	template class Bert<half>;
711	#ifdef ENABLE_BF16
712	template class Bert<__nv_bfloat16>;
713	#endif
714	
715	}  // namespace fastertransformer
