20	
21	template<typename T>
22	void generate_encoder_gemm_config(
23	    int batch_size, int seq_len, int head_num, int size_per_head, void* buffer_in, bool isAppend, int tensor_para_size)
24	{
25	    void* cublas_workspace;
26	    void* buffer;
27	    int   workSpaceSize;
28	
29	#ifdef ENABLE_BF16
30	    if (std::is_same<T, half>::value || std::is_same<T, __nv_bfloat16>::value) {
31	#else
32	    if (std::is_same<T, half>::value) {
33	#endif  // ENABLE_BF16
34	        // cublas_workspace_ should be the start pointer of cudaMalloc()
35	        // to ensure 16B alignemnet
36	        cublas_workspace = buffer_in;
37	        buffer           = (void*)((char*)cublas_workspace + CUBLAS_WORKSPACE_SIZE);
38	        workSpaceSize    = CUBLAS_WORKSPACE_SIZE;
39	    }
40	    else {
41	        cublas_workspace = nullptr;
42	        buffer           = buffer_in;
43	        workSpaceSize    = 0;
44	    }
45	
46	    struct cudaDeviceProp prop;
47	    check_cuda_error(cudaGetDeviceProperties(&prop, 0));
48	    printf("Device %s\n", prop.name);
49	
50	    // check config
51	    FILE* fd;
52	    int   line_count = 0;
53	    if (!isAppend) {
54	        fd = fopen(GEMM_CONFIG, "w+");
55	    }
56	    else {
57	        fd = fopen(GEMM_CONFIG, "a+");
58	        std::vector<std::string> config;
59	        char                     line[1024];
60	        while (fgets(line, 1024, fd) != NULL) {
61	            config.push_back(std::string(line));
62	        }
63	        line_count = config.size();
64	        if (config.size() >= (MAX_CONFIG_NUM * GEMM_NUM + 1))  // 6 cublas/cublasLt, first row is not included
65	        {
66	            int startIdx = config.size() - ((MAX_CONFIG_NUM - 1) * GEMM_NUM);
67	            fclose(fd);
68	            fd = fopen(GEMM_CONFIG, "w+");
69	            fprintf(fd, "%s", config[0].c_str());
70	            for (uint i = startIdx; i < config.size(); i++) {
71	                fprintf(fd, "%s", config[i].c_str());
72	            }
73	            line_count = config.size() - (GEMM_NUM + 3);
74	        }
75	    }
76	
77	    const int gemm_num = 7;
78	    int       M[gemm_num];
79	    int       N[gemm_num];
80	    int       K[gemm_num];
81	    int       batchCount[gemm_num] = {1, 1, 1, 1, 1, 1, 1};
82	    char      mess[gemm_num][256];
83	    float     exec_times[gemm_num];
84	
85	    // gemm1
86	    M[0] = batch_size * seq_len;
87	    K[0] = head_num * size_per_head;
88	    N[0] = (head_num / tensor_para_size) * size_per_head;
89	    strcpy(mess[0], "from_tensor * weightQ/K/V");
90	
91	    // gemm2
92	    M[1] = M[0];
93	    K[1] = head_num * size_per_head;
94	    N[1] = 4 * head_num * size_per_head / tensor_para_size;
95	    strcpy(mess[1], "attr_output * inter_kernel");
96	
97	    // gemm3
98	    M[2] = M[0];
99	    K[2] = 4 * head_num * size_per_head / tensor_para_size;
100	    N[2] = head_num * size_per_head;
101	    strcpy(mess[2], "inter_matmul * output_kernel");
102	
103	    M[3]          = seq_len;
104	    N[3]          = seq_len;
105	    K[3]          = size_per_head;
106	    batchCount[3] = batch_size * (head_num / tensor_para_size);
107	    strcpy(mess[3], "attention batched Gemm1");
108	
109	    M[4]          = seq_len;
110	    N[4]          = size_per_head;
111	    K[4]          = seq_len;
112	    batchCount[4] = batch_size * (head_num / tensor_para_size);
113	    strcpy(mess[4], "attention batched Gemm2");
114	
115	    M[5]          = batch_size * seq_len;
116	    N[5]          = (head_num / tensor_para_size) * size_per_head;
117	    K[5]          = head_num * size_per_head;
118	    batchCount[5] = 3;
119	    strcpy(mess[5], "from_tensor * weight_QKV in BatchGemm");
120	
121	    M[6] = batch_size * seq_len;
122	    K[6] = (head_num / tensor_para_size) * size_per_head;
123	    N[6] = head_num * size_per_head;
124	    strcpy(mess[6], "attr * output_kernel");
125	
126	    cublasHandle_t cublas_handle;
127	    check_cuda_error(cublasCreate(&cublas_handle));
128	    cublasLtHandle_t ltHandle;
129	    check_cuda_error(cublasLtCreate(&ltHandle));
130	
131	    cudaDataType_t AType;
132	    cudaDataType_t BType;
133	    cudaDataType_t CType;
134	    cudaDataType_t computeType;
135	    int            startAlgo, endAlgo;
136	    const int      ites = 100;
137	    struct timeval start, end;
138	
139	    CublasDataType data_type;
140	    if (std::is_same<T, float>::value) {
141	        data_type   = FLOAT_DATATYPE;
142	        AType       = CUDA_R_32F;
143	        BType       = CUDA_R_32F;
144	        CType       = CUDA_R_32F;
145	        computeType = CUDA_R_32F;
146	        startAlgo   = (int)CUBLAS_GEMM_DEFAULT;
147	        endAlgo     = (int)CUBLAS_GEMM_ALGO23;
148	    }
149	    else if (std::is_same<T, half>::value) {
150	        data_type   = HALF_DATATYPE;
151	        AType       = CUDA_R_16F;
152	        BType       = CUDA_R_16F;
153	        CType       = CUDA_R_16F;
154	        computeType = CUDA_R_32F;
155	        startAlgo   = (int)CUBLAS_GEMM_DEFAULT_TENSOR_OP;
156	        endAlgo     = (int)CUBLAS_GEMM_ALGO15_TENSOR_OP;
157	    }
158	#ifdef ENABLE_BF16
159	    else if (std::is_same<T, __nv_bfloat16>::value) {
160	        data_type   = BFLOAT16_DATATYPE;
161	        AType       = CUDA_R_16BF;
162	        BType       = CUDA_R_16BF;
163	        CType       = CUDA_R_16BF;
164	        computeType = CUDA_R_32F;
165	        startAlgo   = (int)CUBLAS_GEMM_DEFAULT_TENSOR_OP;
166	        endAlgo     = (int)CUBLAS_GEMM_ALGO15_TENSOR_OP;
167	    }
168	#endif
169	    using scaleT = typename ScaleTypeConverter<T, false>::Type;
170	
171	    scaleT alpha = (scaleT)1.0f;
172	    scaleT beta  = (scaleT)0.0f;
173	
174	    printf("***Encoder Gemm Testing Begin***\n");
175	    printf("***Cublas Gemm Testing Begin***\n");
176	    if (line_count == 0) {
177	        fprintf(fd,
178	                "batch_size, seq_len, head_num, size_per_head dataType ### batchCount, n, m, k, algoId, "
179	                "customOption, tile, numSplitsK, swizzle, reductionScheme, workspaceSize, stages, exec_time\n");
180	    }
181	    for (int i = 0; i < gemm_num; ++i) {
182	        // if(i != 0 && i != 5) continue;
183	
184	        int m = M[i], n = N[i], k = K[i];
185	        printf("\n-----------------------------\n");
186	        printf("GEMM test %d: [M: %d, K: %d, N: %d] %s\n", i, m, k, n, mess[i]);
187	        T* d_A = (T*)buffer;
188	        T* d_B = d_A + m * k * batchCount[i];
189	        T* d_C = d_B + k * n * batchCount[i];
190	
191	        // array of pointer for batchedGemm
192	        T* harray[12];
193	        harray[0]  = (T*)buffer;
194	        harray[1]  = (T*)((char*)buffer + sizeof(T) * m * k);
195	        harray[2]  = (T*)((char*)buffer + 2 * sizeof(T) * m * k);
196	        harray[4]  = (T*)((char*)buffer + 3 * sizeof(T) * m * k);
197	        harray[5]  = (T*)((char*)buffer + 3 * sizeof(T) * m * k + sizeof(T) * k * n);
198	        harray[6]  = (T*)((char*)buffer + 3 * sizeof(T) * m * k + 2 * sizeof(T) * k * n);
199	        harray[8]  = (T*)((char*)buffer + 3 * sizeof(T) * m * k + 3 * sizeof(T) * k * n);
200	        harray[9]  = (T*)((char*)buffer + 3 * sizeof(T) * m * k + 3 * sizeof(T) * k * n + sizeof(T) * m * n);
201	        harray[10] = (T*)((char*)buffer + 3 * sizeof(T) * m * k + 3 * sizeof(T) * k * n + 2 * sizeof(T) * m * n);
202	
203	        T** darray = 0;
204	        check_cuda_error(cudaMalloc((void**)&darray, sizeof(T*) * 12));
205	        cudaMemcpy((void*)darray, (void*)harray, sizeof(T*) * 12, cudaMemcpyHostToDevice);
206	        T** dAarray = darray;
207	        T** dBarray = darray + 4;
208	        T** dCarray = darray + 8;
209	
210	        float exec_time = 99999.0f;
211	        int   fast_algo = 0;
212	        for (int algo = startAlgo; algo <= endAlgo; algo++) {
213	            cublasStatus_t status;
214	            cudaDeviceSynchronize();
215	            gettimeofday(&start, NULL);
216	            for (int ite = 0; ite < ites; ++ite) {
217	                if (i < 3) {
218	                    status = cublasGemmEx(cublas_handle,
219	                                          CUBLAS_OP_N,
220	                                          CUBLAS_OP_N,
221	                                          n,
222	                                          m,
223	                                          k,
224	                                          &alpha,
225	                                          d_B,
226	                                          BType,
227	                                          n,
228	                                          d_A,
229	                                          AType,
230	                                          k,
231	                                          &beta,
232	                                          d_C,
233	                                          CType,
234	                                          n,
235	                                          computeType,
236	                                          static_cast<cublasGemmAlgo_t>(algo));
237	                }
238	                else if (i == 3) {
239	                    status = cublasGemmStridedBatchedEx(cublas_handle,
240	                                                        CUBLAS_OP_T,
241	                                                        CUBLAS_OP_N,
242	                                                        seq_len,
243	                                                        seq_len,
244	                                                        size_per_head,
245	                                                        &alpha,
246	                                                        d_B,
247	                                                        BType,
248	                                                        size_per_head,
249	                                                        seq_len * size_per_head,
250	                                                        d_A,
251	                                                        AType,
252	                                                        size_per_head,
253	                                                        seq_len * size_per_head,
254	                                                        &beta,
255	                                                        d_C,
256	                                                        CType,
257	                                                        seq_len,
258	                                                        seq_len * seq_len,
259	                                                        batch_size * head_num,
260	                                                        computeType,
261	                                                        static_cast<cublasGemmAlgo_t>(algo));
262	                }
263	                else if (i == 4) {
264	                    status = cublasGemmStridedBatchedEx(cublas_handle,
265	                                                        CUBLAS_OP_N,
266	                                                        CUBLAS_OP_N,
267	                                                        size_per_head,
268	                                                        seq_len,
269	                                                        seq_len,
270	                                                        &alpha,
271	                                                        d_B,
272	                                                        BType,
273	                                                        size_per_head,
274	                                                        seq_len * size_per_head,
275	                                                        d_A,
276	                                                        AType,
277	                                                        seq_len,
278	                                                        seq_len * seq_len,
279	                                                        &beta,
280	                                                        d_C,
281	                                                        CType,
282	                                                        size_per_head,
283	                                                        seq_len * size_per_head,
284	                                                        batch_size * head_num,
285	                                                        computeType,
286	                                                        static_cast<cublasGemmAlgo_t>(algo));
287	                }
288	                else if (i == 5) {
289	                    status = cublasGemmBatchedEx(cublas_handle,
290	                                                 CUBLAS_OP_N,
291	                                                 CUBLAS_OP_N,
292	                                                 n,
293	                                                 m,
294	                                                 k,
295	                                                 &alpha,
296	                                                 (const void* const*)dBarray,
297	                                                 BType,
298	                                                 n,
299	                                                 (const void* const*)dAarray,
300	                                                 AType,
301	                                                 k,
302	                                                 &beta,
303	                                                 (void* const*)dCarray,
304	                                                 CType,
305	                                                 n,
306	                                                 3,
307	                                                 computeType,
308	                                                 static_cast<cublasGemmAlgo_t>(algo));
309	                }
310	                if (status != CUBLAS_STATUS_SUCCESS) {
311	                    break;
312	                }
313	            }
314	            cudaDeviceSynchronize();
315	            gettimeofday(&end, NULL);
316	            if (status == CUBLAS_STATUS_SUCCESS) {
317	                printf("algo_%d costs %.3fms \n", algo, diffTime(start, end) / ites);
318	                if (diffTime(start, end) / ites < exec_time) {
319	                    exec_time = diffTime(start, end) / ites;
320	                    fast_algo = algo;
321	                }
322	            }
323	        }
324	        printf("fast_algo %d costs %.3f ms\n", fast_algo, exec_time);
325	
326	        // for fp16 and bf16, we compare cublasLt
327	        if (i < 3 && data_type != FLOAT_DATATYPE) {
328	            printf("***cublasLt Gemm Testing Begin***\n");
329	            // Let try a fixed number of combinations
330	            int                ALGO_COMBINATIONS = 5000;
331	            customMatmulPerf_t perfResults[ALGO_COMBINATIONS];
332	            LtHgemmCustomFind<T, scaleT>(ltHandle,
333	                                         batch_size,
334	                                         seq_len,
335	                                         head_num,
336	                                         size_per_head,
337	                                         n,
338	                                         m,
339	                                         k,
340	                                         &alpha,
341	                                         d_B,
342	                                         d_A,
343	                                         &beta,
344	                                         d_C,
345	                                         cublas_workspace,
346	                                         workSpaceSize,
347	                                         fd,
348	                                         perfResults,
349	                                         ALGO_COMBINATIONS);
350	            if (perfResults[0].time < exec_time) {
351	                printPerfStructure(
352	                    batch_size, seq_len, head_num, size_per_head, n, m, k, perfResults[0], fd, data_type, 0);
353	                exec_time = perfResults[0].time;
354	            }
355	            else {
356	                fprintf(fd,
357	                        "%d %d %d %d %d ### %d %d %d %d %d -1 -1 -1 -1 -1 -1 -1 "
358	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
359	                        "-1 -1 "
360	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
361	                        "-1 -1 -1 "
362	#endif
363	                        "%f\n",
364	                        batch_size,
365	                        seq_len,
366	                        head_num,
367	                        size_per_head,
368	                        data_type,
369	                        batchCount[i],
370	                        n,
371	                        m,
372	                        k,
373	                        fast_algo,
374	                        exec_time);
375	            }
376	            printf("***cublasLt Gemm Testing End***\n");
377	        }
378	        else {
379	            fprintf(fd,
380	                    "%d %d %d %d %d ### %d %d %d %d %d -1 -1 -1 -1 -1 -1 -1 "
381	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
382	                    "-1 -1 "
383	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
384	                    "-1 -1 -1 "
385	#endif
386	                    "%f\n",
387	                    batch_size,
388	                    seq_len,
389	                    head_num,
390	                    size_per_head,
391	                    data_type,
392	                    batchCount[i],
393	                    n,
394	                    m,
395	                    k,
396	                    fast_algo,
397	                    exec_time);
398	        }
399	        exec_times[i] = exec_time;
400	        cudaFree(darray);
401	    }
402	    printf("***cublas Gemm Testing End***\n\n");
403	    fclose(fd);
404	    printf("***Encoder Gemm Testing End***\n");
405	
406	#ifdef SPARSITY_ENABLED
407	    bool do_sparse_test = false;
408	    if (prop.major == 8 && (prop.minor == 0 || prop.minor == 6)) {
409	        do_sparse_test = true;
410	    }
411	    if (do_sparse_test && sizeof(T) == sizeof(half)) {
412	        printf("***cusparseLt Gemm Testing Begin***\n");
413	        // only first 3 cases can be sparse
414	        const int spgemm_num = 3;
415	        if (!isAppend) {
416	            fd = fopen(SPGEMM_CONFIG, "w+");
417	        }
418	        else {
419	            fd = fopen(SPGEMM_CONFIG, "a+");
420	            std::vector<std::string> config;
421	            char                     line[1024];
422	            while (fgets(line, 1024, fd) != NULL) {
423	                config.push_back(std::string(line));
424	            }
425	            line_count = config.size();
426	            if (config.size() >= (MAX_CONFIG_NUM * spgemm_num + 1))  // 6 cublas/cublasLt, first row is not included
427	            {
428	                int startIdx = config.size() - ((MAX_CONFIG_NUM - 1) * spgemm_num);
429	                fclose(fd);
430	                fd = fopen(SPGEMM_CONFIG, "w+");
431	                fprintf(fd, "%s", config[0].c_str());
432	                for (uint i = startIdx; i < config.size(); i++) {
433	                    fprintf(fd, "%s", config[i].c_str());
434	                }
435	                line_count = config.size() - (spgemm_num + 3);
436	            }
437	        }
438	        if (line_count == 0) {
439	            fprintf(
440	                fd,
441	                "batch_size, seq_len, head_num, size_per_head dataType ### batchCount, m, n, k, algoId, exec_time\n");
442	        }
443	        cusparseLtHandle_t handle;
444	        CHECK_CUSPARSE(cusparseLtInit(&handle));
445	        cusparseOrder_t     order        = CUSPARSE_ORDER_COL;
446	        cusparseOperation_t opA          = CUSPARSE_OPERATION_NON_TRANSPOSE;
447	        cusparseOperation_t opB          = CUSPARSE_OPERATION_NON_TRANSPOSE;
448	        cusparseComputeType compute_type = CUSPARSE_COMPUTE_16F;
449	        unsigned            alignment    = 16;
450	        cudaStream_t        stream       = 0;
451	        float               alpha2       = 1.0f;
452	        float               beta2        = 0.0f;
453	        for (int i = 0; i < spgemm_num; ++i) {
454	            // to be compatible with spgemm wrapper, we let A be the weight matrix
455	            // so m and n are swapped
456	            // A: mxk B: kxn C:mxn
457	            int m = N[i], n = M[i], k = K[i];
458	            printf("\n-----------------------------\n");
459	            printf("GEMM test %d: [M: %d, K: %d, N: %d]\n", i, m, k, n);
460	            T* d_A = (T*)buffer;
461	            T* d_B = d_A + m * k * batchCount[i];
462	            T* d_C = d_B + k * n * batchCount[i];
463	            T* dA_compressed;
464	            {
465	                cusparseLtMatDescriptor_t matA;
466	                CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(
467	                    &handle, &matA, m, k, m, alignment, CUDA_R_16F, order, CUSPARSELT_SPARSITY_50_PERCENT))
468	                CHECK_CUSPARSE(
469	                    cusparseLtSpMMAPrune2(&handle, &matA, true, opA, d_A, d_A, CUSPARSELT_PRUNE_SPMMA_STRIP, stream))
470	                size_t compressed_size;
471	                CHECK_CUSPARSE(cusparseLtSpMMACompressedSize2(&handle, &matA, &compressed_size))
472	                check_cuda_error(cudaMalloc((void**)&dA_compressed, compressed_size));
473	                CHECK_CUSPARSE(cusparseLtSpMMACompress2(&handle, &matA, true, opA, d_A, dA_compressed, stream))
474	            }
475	
476	            float exec_time = 99999.0f;
477	            int   fast_algo = 0;
478	            for (int alg = 0; alg < 4; ++alg) {
479	                cudaDeviceSynchronize();
480	                cusparseLtMatDescriptor_t matA, matB, matC;
481	                void*                     d_workspace = nullptr;
482	                int                       num_streams = 1;
483	                cudaStream_t              streams[1]  = {stream};
484	                CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(
485	                    &handle, &matA, m, k, m, alignment, CUDA_R_16F, order, CUSPARSELT_SPARSITY_50_PERCENT))
486	                CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(&handle, &matB, k, n, k, alignment, CUDA_R_16F, order))
487	                CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(&handle, &matC, m, n, m, alignment, CUDA_R_16F, order))
488	                gettimeofday(&start, NULL);
489	                for (int ite = 0; ite < ites; ++ite) {
490	                    // initializing MatDesc takes a lot of time
491	                    // and these descs can be stored to other place
492	                    // whereas storing MatMulPlan to other place will cause errors
493	                    cusparseLtMatmulDescriptor_t   matmul;
494	                    cusparseLtMatmulAlgSelection_t alg_sel;
495	                    cusparseLtMatmulPlan_t         plan;
496	                    CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(
497	                        &handle, &matmul, opA, opB, &matA, &matB, &matC, &matC, compute_type))
498	                    CHECK_CUSPARSE(
499	                        cusparseLtMatmulAlgSelectionInit(&handle, &alg_sel, &matmul, CUSPARSELT_MATMUL_ALG_DEFAULT))
500	                    CHECK_CUSPARSE(cusparseLtMatmulAlgSetAttribute(
501	                        &handle, &alg_sel, CUSPARSELT_MATMUL_ALG_CONFIG_ID, &alg, sizeof(alg)))
502	                    size_t workspace_size;
503	                    CHECK_CUSPARSE(cusparseLtMatmulGetWorkspace(&handle, &alg_sel, &workspace_size))
504	                    CHECK_CUSPARSE(cusparseLtMatmulPlanInit(&handle, &plan, &matmul, &alg_sel, workspace_size))
505	                    CHECK_CUSPARSE(cusparseLtMatmul(&handle,
506	                                                    &plan,
507	                                                    &alpha2,
508	                                                    dA_compressed,
509	                                                    d_B,
510	                                                    &beta2,
511	                                                    d_C,
512	                                                    d_C,
513	                                                    d_workspace,
514	                                                    streams,
515	                                                    num_streams))
516	                    CHECK_CUSPARSE(cusparseLtMatmulPlanDestroy(&plan))
517	                }
518	                cudaDeviceSynchronize();
519	                gettimeofday(&end, NULL);
520	                printf("algo_%d costs %.3fms \n", alg, diffTime(start, end) / ites);
521	                if (diffTime(start, end) < exec_time) {
522	                    exec_time = diffTime(start, end);
523	                    fast_algo = alg;
524	                }
525	            }
526	            exec_time /= ites;
527	            if (exec_time >= exec_times[i]) {
528	                fast_algo = -1;
529	            }
530	            printf("fast_algo %d\n", fast_algo);
531	            fprintf(fd,
532	                    "%d %d %d %d %d ### %d %d %d %d %d %f\n",
533	                    batch_size,
534	                    seq_len,
535	                    head_num,
536	                    size_per_head,
537	                    HALF_DATATYPE,
538	                    batchCount[i],
539	                    m,
540	                    n,
541	                    k,
542	                    fast_algo,
543	                    exec_time);
544	            cudaFree(dA_compressed);
545	        }
546	        CHECK_CUSPARSE(cusparseLtDestroy(&handle))
547	        fclose(fd);
548	        printf("***cusparseLt Gemm Testing End***\n");
549	    }
550	#endif
551	    return;
552	}
553	
554	template void generate_encoder_gemm_config<float>(
555	    int batch_size, int seq_len, int head_num, int size_per_head, void* buffer, bool isAppend, int tensor_para_size);
556	template void generate_encoder_gemm_config<half>(
557	    int batch_size, int seq_len, int head_num, int size_per_head, void* buffer, bool isAppend, int tensor_para_size);
558	#ifdef ENABLE_BF16
559	template void generate_encoder_gemm_config<__nv_bfloat16>(
560	    int batch_size, int seq_len, int head_num, int size_per_head, void* buffer, bool isAppend, int tensor_para_size);
561	#endif
562	
563	}  // namespace fastertransformer
